  <!-- BLOG MODALS ─────────────────────────────────────────────────────────── -->
  <?php if ($blogEnabled): ?>

  <!-- Blog list popup: all posts -->
  <div class="blog-list-modal" id="blog-list-modal" role="dialog" aria-modal="true" aria-label="Alle Beiträge"
