      <?php if (!empty($allBlogPosts)): ?>
      <div class="blog-list-modal__list">
        <?php foreach ($allBlogPosts as $_lp):
          $_lCover = $_lp['cover_path'] ? $base . '/cms/uploads/' . $_lp['cover_path'] : '';
          $_lDate  = $_lp['published_at']
                       ? date('d. M. Y', strtotime($_lp['published_at']))
                       : date('d. M. Y', strtotime($_lp['created_at']));
