        </button>
        <?php endforeach; ?>
      </div>
      <?php else: ?>
      <div class="blog-list-modal__empty">Noch keine Beiträge veröffentlicht.</div>
      <?php endif; ?>
    </div>
  </div>

  <!-- Blog article popup: single post -->
  <div class="blog-modal" id="blog-modal" role="dialog" aria-modal="true" aria-label="Artikel"
       onclick="if(event.target===this)closeBlogPost()">
    <div class="blog-modal__panel">
      <button class="blog-modal__close" onclick="closeBlogPost()" aria-label="Schließen">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round">
          <line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>
        </svg>
      </button>
      <img id="blog-modal-cover" class="blog-modal__cover" alt="" style="display:none">
      <div class="blog-modal__meta">
        <span class="blog-modal__cat"  id="blog-modal-cat"  style="display:none"></span>
        <span class="blog-modal__date" id="blog-modal-date"></span>
      </div>
      <h2 class="blog-modal__title"   id="blog-modal-title"></h2>
      <div class="blog-modal__divider" aria-hidden="true"></div>
      <div class="blog-modal__body"   id="blog-modal-body"></div>
    </div>
  </div>

  <script>
  /* Blog post data — ALL published posts embedded server-side */
  const _BLOG_POSTS = <?= json_encode(array_values($allBlogPosts), JSON_HEX_TAG | JSON_HEX_AMP | JSON_HEX_APOS) ?>;
  const _BLOG_BASE  = <?= json_encode($base) ?>;

  /* ── Blog list popup ── */
  function openBlogList() {
    document.getElementById('blog-list-modal').classList.add('is-open');
    document.body.style.overflow = 'hidden';
  }
  function closeBlogList() {
    document.getElementById('blog-list-modal').classList.remove('is-open');
    document.body.style.overflow = '';
  }
  function openBlogPostFromList(id) {
    closeBlogList();
    openBlogPost(id);
  }

  /* ── Individual blog post popup ── */
  function openBlogPost(id) {
    const post = _BLOG_POSTS.find(p => p.id == id);
    if (!post) return;
    const modal  = document.getElementById('blog-modal');
    const cover  = document.getElementById('blog-modal-cover');
    const cat    = document.getElementById('blog-modal-cat');
    const date   = document.getElementById('blog-modal-date');
    const title  = document.getElementById('blog-modal-title');
    const body   = document.getElementById('blog-modal-body');
    if (post.cover_path) {
      cover.src          = _BLOG_BASE + '/cms/uploads/' + post.cover_path;
      cover.style.display = 'block';
    } else {
      cover.style.display = 'none';
    }
    if (post.topic) {
      cat.textContent   = post.topic;
      cat.style.display = '';
    } else {
      cat.style.display = 'none';
    }
    const rawDate = post.published_at || post.created_at;
    date.textContent = rawDate
      ? new Date(rawDate).toLocaleDateString('de-DE', {day:'2-digit', month:'long', year:'numeric'})
      : '';
    title.textContent = post.title;
    body.innerHTML    = post.body_html || '';
    modal.scrollTop   = 0;
    modal.classList.add('is-open');
    document.body.style.overflow = 'hidden';
  }

  function closeBlogPost() {
    document.getElementById('blog-modal').classList.remove('is-open');
    document.body.style.overflow = '';
  }

  /* Close on Escape */
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape') { closeBlogList(); closeBlogPost(); }
  });
  </script>
  <?php endif; ?>
```

